@Controller
class SamlController {
    private final SamlService samlService;

    SamlController(SamlService samlService) {
        this.samlService = samlService;
    }

    @GetMapping("/")
    public void home(HttpServletResponse response) throws Exception {
        response.setContentType("text/html");
        response.getWriter().write("<html><body><a href='/saml/login'>Login with SSO</a></body></html>");
    }

    @GetMapping("/saml/login")
    public void login(HttpServletResponse response) throws Exception {
        response.sendRedirect(samlService.buildAuthnRequestRedirectUrl());
    }

    @PostMapping("/saml/acs")
    public void acs(@RequestParam("SAMLResponse") String samlResponse, HttpServletResponse response) throws Exception {
        SamlUser user = samlService.processSamlResponse(samlResponse);
        response.setContentType("application/json");
        response.getWriter().write("{\"nameId\":\"" + escape(user.getNameId()) + "\",\"attributes\":" + toJson(user.getAttributes()) + "}");
    }

    @GetMapping(value = "/saml/metadata", produces = MediaType.APPLICATION_XML_VALUE)
    public void metadata(HttpServletResponse response) throws Exception {
        response.setContentType(MediaType.APPLICATION_XML_VALUE);
        response.getWriter().write(samlService.generateMetadata());
    }

    private String toJson(java.util.Map<String, String> map) {
        StringBuilder sb = new StringBuilder("{");
        boolean first = true;
        for (java.util.Map.Entry<String, String> e : map.entrySet()) {
            if (!first) sb.append(",");
            sb.append("\"").append(escape(e.getKey())).append("\":\"").append(escape(e.getValue())).append("\"");
            first = false;
        }
        sb.append("}");
        return sb.toString();
    }

    private String escape(String s) {
        if (s == null) return "";
        return s.replace("\\", "\\\\").replace("\"", "\\\"");
    }
}